option.value:
/* 优化后的 Obsidian 彩色方案 (适用于 Rider) */

/* 一级标题：柔粉红 */
h1 {
    color: #eb6f92 !important;
    border-bottom: 1px solid #31748f !important;
    font-weight: 700;
}

/* 二级标题：浅蓝 */
h2 {
    color: #8ccad4 !important;
    border-bottom: none !important;
}

/* 浅绿色 */
h3 {
    color: #abcf96 !important;
}

/* 浅紫色 */
h4 {
    color: #c4a7e7 !important;
}

/* 浅粉/橙 */
h5 {
    color: #ebbcba !important;
}

/* 珊瑚色 */
h6 {
    color: #908caa !important;
}

/* 超链接：使用明亮的青蓝色 */
a {
    color: #dd95aa !important;
    text-decoration: none !important;
    border-bottom: 3px dashed #a780a7 !important;
    transition: all 0.2s ease-in-out;
}

a:hover {
    color: #eb6f92 !important;
    border-bottom: 1px solid #eb6f92 !important;
    background-color: rgba(235, 111, 146, 0.1) !important;
}

/* 加粗文字颜色：浅橙 */
strong, b {
    color: rgb(238, 203, 162) !important;
}

/* 代码块背景稍微提亮 */
code {
    padding: 2px 4px;
    border-radius: 4px;
}
